mapper.select:
SELECT * FROM training_record
WHERE is_deleted = 0
AND train_date >= #{startDate}
AND train_date <= #{endDate}
AND user_id = #{userId}
ORDER BY train_date DESC, create_time DESC

mapper.update:
UPDATE training_record
SET train_date = #{trainDate}, duration = #{duration}, notes = #{notes}
WHERE id = #{id}

UPDATE training_record
SET is_completed = 1, total_sets = #{totalSets}, total_reps = #{totalReps}
WHERE id = #{id}
